import json, re, subprocess, os

lines = open('ios_crash.ips').readlines()
metadata = json.loads(lines[0])
raw_body = ''.join(lines[1:])
raw_body = re.sub(r'\"vmregioninfo\"', '\"vmregioninfo_lower\"', raw_body)
crash = json.loads(raw_body)
images = crash.get('usedImages', [])

# .NET runtime images to symbolicate (not including app binary - needs build dSYM)
dotnet_libs = {
    'libcoreclr': None,
    'libSystem.Globalization.Native': None,
    'libSystem.IO.Compression.Native': None,
    'libSystem.Native': None,
    'libSystem.Net.Security.Native': None,
    'libSystem.Security.Cryptography.Native.Apple': None,
}

for i, img in enumerate(images):
    name = img.get('name', '')
    for prefix in dotnet_libs:
        if prefix in name:
            uuid = img.get('uuid', '').replace('-', '').lower()
            dotnet_libs[prefix] = {'uuid': uuid, 'base': hex(img.get('base',0)), 'arch': img.get('arch','arm64'), 'index': i}
            break

# Download symbols from Microsoft symbol server
os.makedirs('symbols', exist_ok=True)
for lib_name, info in dotnet_libs.items():
    if info is None:
        continue
    uuid = info['uuid']
    url = f'https://msdl.microsoft.com/download/symbols/_.dwarf/mach-uuid-sym-{uuid}/_.dwarf'
    dsym_dir = f'symbols/{lib_name}.dSYM/Contents/Resources/DWARF'
    os.makedirs(dsym_dir, exist_ok=True)
    out_file = f'{dsym_dir}/{lib_name}'
    if not os.path.exists(out_file):
        result = subprocess.run(['curl', '-sS', '-f', '-o', out_file, url], capture_output=True, text=True)
        if result.returncode == 0:
            print(f'Downloaded: {lib_name} (uuid={uuid})')
        else:
            print(f'FAILED: {lib_name} (uuid={uuid}) - {result.stderr.strip()}')
    else:
        print(f'Cached: {lib_name}')
